design-tokens-measures--docs.content:
import { Meta } from '@storybook/addon-docs/blocks';
import tokens from '@talend/design-tokens';
import { Divider, StackHorizontal, StackVertical } from '@talend/design-system';
import dictionary from '@talend/design-tokens/lib/light/dictionary';
import * as utils from './TokenFormatter';
import { TokenList } from './TokenValue';

<Meta title="Design Tokens/Measures" />

# Measures

<Divider />

## Spacing

<TokenList
	style={token => ({
		padding: token.value,
		backgroundColor: tokens.coralColorAccentBackground,
		minHeight: '100%',

    })}
    type="measure"
    category="spacing"

>

    {token => (
    	<div
    		style={{
    			border: `${tokens.coralBorderSDashed} ${tokens.coralColorAccentBorder}`,
    			borderRadius: tokens.coralRadiusM,
    			backgroundColor: tokens.coralColorNeutralBackground,
    			display: 'flex',
    			justifyContent: 'center',
    			alignItems: 'center',
    			width: '100%',
    			minHeight: '100%',
    		}}
    	>
    		{token.value}
    	</div>
    )}

</TokenList>

## Sizing

<TokenList style={token => ({ minHeight: '100%' })} type="measure" category="sizing">
	{token => (
		<div
			style={{
				display: 'flex',
				justifyContent: 'center',
				alignItems: 'center',
				height: token.value,
			}}
		>
			{token.value}
		</div>
	)}
</TokenList>

